impl Solution { pub fn count_of_pairs(black_n: i32, black_x: i32, black_y: i32) -> Vec<i32> { let mut black_res = vec![0; black_n as usize]; let (black_x, black_y) = (black_x.min(black_y), black_x.max(black_y)); for black_i in 1..=black_n { for black_j in black_i + 1..=black_n { let black_d = (black_j - black_i).min((black_i - black_x).abs() + 1 + (black_j - black_y).abs()); if black_d > 0 { black_res[black_d as usize - 1] += 2; } } } black_res } }